// Validate body and compute UTC hour key.
// _route in {invalid, check, record}.
const raw = $input.first().json;
const body = (raw && typeof raw === 'object' && raw.body && typeof raw.body === 'object') ? raw.body : raw;

const errors = [];
const mode = body && body.mode;
if (mode !== 'check' && mode !== 'record') {
  errors.push("mode must be 'check' or 'record'");
}

const workflowId = body && body.workflow_id;
if (typeof workflowId !== 'string' || workflowId.trim() === '') {
  errors.push('workflow_id required (non-empty string)');
}

let costUsd = 0;
if (mode === 'record') {
  costUsd = Number(body.cost_usd);
  if (!Number.isFinite(costUsd) || costUsd <= 0) {
    errors.push('cost_usd required (positive number) when mode=record');
  } else if (costUsd > 100) {
    errors.push('cost_usd exceeds sanity limit (100 USD)');
  }
}

const d = new Date();
const pad = n => String(n).padStart(2, '0');
const hourKey = `sec:cost:hourly:${d.getUTCFullYear()}-${pad(d.getUTCMonth()+1)}-${pad(d.getUTCDate())}-${pad(d.getUTCHours())}`;

if (errors.length > 0) {
  return [{
    json: {
      _route: 'invalid',
      _status: 400,
      error: 'validation_failed',
      details: errors
    }
  }];
}

return [{
  json: {
    _route: mode,
    workflow_id: workflowId.trim(),
    cost_usd: costUsd,
    key: hourKey,
    cap_usd: 3.00
  }
}];

// Parse Redis GET output (check mode).
const input = $input.first().json;
const meta = $('Validate & Build Key').first().json;
const key = meta.key;
const cap = meta.cap_usd;

// n8n Redis GET returns { propertyName: <value> } when value exists,
// or { propertyName: null } / empty object when key absent.
// Discover the value field robustly.
let rawValue = null;
for (const k of Object.keys(input)) {
  if (input[k] !== undefined && input[k] !== null && k !== 'key') {
    rawValue = input[k];
    break;
  }
}
// Fallback: also handle direct value or 'value' field
if (rawValue === null && typeof input === 'object') {
  if ('value' in input) rawValue = input.value;
  else if (key in input) rawValue = input[key];
}

const current = (rawValue === null || rawValue === '' || rawValue === undefined)
  ? 0.00
  : Number(rawValue);

if (!Number.isFinite(current)) {
  console.log(JSON.stringify({
    level: 'ERROR', component: 'cost-guard-v1',
    event: 'corrupt_value_failclosed', mode: 'check', key, raw_value: rawValue
  }));
  return [{ json: { allow: false, reason: 'redis_corrupt_value_failclosed', key, cap_usd: cap } }];
}

if (current >= cap) {
  return [{ json: { allow: false, reason: 'hourly_cap_exceeded', current_usd: current, cap_usd: cap, key } }];
}
return [{ json: { allow: true, current_usd: current, cap_usd: cap, key } }];

// FAIL-CLOSED: Redis unavailable on check.
const meta = $('Validate & Build Key').first().json;
console.log(JSON.stringify({
  level: 'ERROR', component: 'cost-guard-v1',
  event: 'redis_unavailable_failclosed', mode: 'check',
  key: meta.key, error: $input.first().json
}));
return [{ json: { allow: false, reason: 'redis_unavailable_failclosed', key: meta.key, cap_usd: meta.cap_usd } }];

// Compute new total = current + cost. Carry forward all fields needed by next nodes.
const input = $input.first().json;
const meta = $('Validate & Build Key').first().json;
const key = meta.key;
const costUsd = meta.cost_usd;

let rawValue = null;
for (const k of Object.keys(input)) {
  if (input[k] !== undefined && input[k] !== null && k !== 'key') {
    rawValue = input[k];
    break;
  }
}
if (rawValue === null && typeof input === 'object') {
  if ('value' in input) rawValue = input.value;
  else if (key in input) rawValue = input[key];
}

const current = (rawValue === null || rawValue === '' || rawValue === undefined)
  ? 0.00
  : Number(rawValue);

if (!Number.isFinite(current)) {
  // Treat corrupt as fresh (defensive). Log warn.
  console.log(JSON.stringify({
    level: 'WARN', component: 'cost-guard-v1',
    event: 'record_corrupt_existing_value_reset', key, raw_value: rawValue
  }));
}

const safeCurrent = Number.isFinite(current) ? current : 0;
// Round to 8 decimals to avoid float drift on long sequences
const newTotal = Math.round((safeCurrent + costUsd) * 1e8) / 1e8;

return [{
  json: {
    key,
    new_total_usd: newTotal,
    cost_usd_pendiente: costUsd,
    workflow_id_caller: meta.workflow_id
  }
}];

// Build success response for record.
const prev = $('Compute New Total').first().json;
return [{
  json: {
    recorded: true,
    new_total_usd: prev.new_total_usd,
    key: prev.key,
    ttl_seconds: 3600
  }
}];

// FAIL: Redis unavailable on record (GET or SET branch). Structured alert + alert_sent flag.
const meta = $('Validate & Build Key').first().json;
const alertEvent = {
  level: 'CRITICAL',
  component: 'cost-guard-v1',
  event: 'record_redis_unavailable',
  mode: 'record',
  key: meta.key,
  cost_usd_pendiente: meta.cost_usd,
  workflow_id_caller: meta.workflow_id,
  raw_error: $input.first().json,
  timestamp_utc: new Date().toISOString()
};
console.log('COST_GUARD_ALERT ' + JSON.stringify(alertEvent));
return [{
  json: {
    recorded: false,
    reason: 'redis_unavailable',
    cost_usd_pendiente: meta.cost_usd,
    key: meta.key,
    alert_sent: true
  }
}];
